description:
The result returned by the optimization solver.

Contains the optimized schedule along with detailed scoring information that shows how well the solution satisfies the objectives and constraints. The schedule format uses nested HashMaps for easy programmatic access.

# Schedule Format

The schedule is structured as: ```text schedule["session_0"]["Group1"] = ["Alice", "Bob", "Charlie"] schedule["session_0"]["Group2"] = ["Diana", "Eve", "Frank"] schedule["session_1"]["Group1"] = ["Alice", "Diana", "Grace"] ... ```

# Example

```no_run use solver_core::{run_solver, models::*}; use std::collections::HashMap;

// ... create input configuration ... # let input = ApiInput { #     initial_schedule: None, #     problem: ProblemDefinition { people: vec![], groups: vec![], num_sessions: 1 }, #     objectives: vec![], constraints: vec![], #     solver: SolverConfiguration { #         solver_type: "SimulatedAnnealing".to_string(), #         stop_conditions: StopConditions { max_iterations: Some(1000), time_limit_seconds: None, no_improvement_iterations: None }, #         solver_params: SolverParams::SimulatedAnnealing(SimulatedAnnealingParams { initial_temperature: 10.0, final_temperature: 0.1, cooling_schedule: "geometric".to_string(), reheat_after_no_improvement: Some(0), reheat_cycles: Some(0) }), #         logging: LoggingOptions::default(), #         telemetry: Default::default(), #         seed: None, #         move_policy: None, #         allowed_sessions: None, #     }, # };

match run_solver(&input) { Ok(result) => { println!("Final score: {}", result.final_score); println!("Unique contacts: {}", result.unique_contacts); println!("Repetition penalty: {}", result.repetition_penalty);

// Display the schedule println!("Schedule:\n{}", result.display());

// Access specific assignments programmatically if let Some(session_0) = result.schedule.get("session_0") { if let Some(group_1) = session_0.get("Group1") { println!("Group1 in session 0: {:?}", group_1); } } } Err(e) => eprintln!("Error: {:?}", e), } ```
